using Dapper;
using Valora.Application.Contracts;
using Valora.Application.DTOs;
namespace Valora.Infrastructure.Repositories;
public sealed class ReportRepository(IDbConnectionFactory f):IReportRepository{ public async Task<IReadOnlyList<ReportDefinitionDto>> ListDefinitionsAsync(){using var c=f.Create(); return (await c.QueryAsync<ReportDefinitionDto>("SELECT id,code,name,description,report_type AS ReportType,required_module_code AS RequiredModuleCode,minimum_plan_code AS MinimumPlanCode,status FROM valorapesquisa.report_definitions WHERE is_deleted=false")).ToList();} public async Task<GeneratedReportDto> CreateGeneratedAsync(Guid o,Guid? s,Guid? r,Guid? d,string title,string format,string payloadJson,Guid? u){using var c=f.Create(); return await c.QuerySingleAsync<GeneratedReportDto>(@"INSERT INTO valorapesquisa.generated_reports(organization_id,survey_id,response_id,report_definition_id,title,format,status,generated_by,generated_at,payload_json,file_name,mime_type) VALUES(@o,@s,@r,@d,@title,@format,'generated',@u,now(),CAST(@payloadJson AS jsonb),@file,@mime) RETURNING id,organization_id OrganizationId,survey_id SurveyId,response_id ResponseId,title,format,status,payload_json::text PayloadJson,file_name FileName,mime_type MimeType,created_at CreatedAt",new{o,s,r,d,title,format,payloadJson,u,file=$"report-{DateTime.UtcNow:yyyyMMddHHmmss}.{format}",mime=format=="json"?"application/json":format=="csv"?"text/csv":"text/html"});} public async Task<IReadOnlyList<GeneratedReportDto>> ListGeneratedAsync(Guid o){using var c=f.Create(); return (await c.QueryAsync<GeneratedReportDto>("SELECT id,organization_id OrganizationId,survey_id SurveyId,response_id ResponseId,title,format,status,payload_json::text PayloadJson,file_name FileName,mime_type MimeType,created_at CreatedAt FROM valorapesquisa.generated_reports WHERE organization_id=@o ORDER BY created_at DESC",new{o})).ToList();} public async Task<GeneratedReportDto?> GetGeneratedAsync(Guid o,Guid id){using var c=f.Create(); return await c.QueryFirstOrDefaultAsync<GeneratedReportDto>("SELECT id,organization_id OrganizationId,survey_id SurveyId,response_id ResponseId,title,format,status,payload_json::text PayloadJson,file_name FileName,mime_type MimeType,created_at CreatedAt FROM valorapesquisa.generated_reports WHERE organization_id=@o AND id=@id",new{o,id});}}
public sealed class CertificateOperationalRepository(IDbConnectionFactory f):ICertificateOperationalRepository{ public async Task<CertificateDto?> GetAsync(Guid o,Guid id){using var c=f.Create(); return await c.QueryFirstOrDefaultAsync<CertificateDto>("SELECT id,organization_id OrganizationId,survey_id SurveyId,response_id ResponseId,participant_name ParticipantName,participant_email_masked ParticipantEmailMasked,company_name CompanyName,total_score TotalScore,level,validation_code ValidationCode,validation_url ValidationUrl,status,issued_at IssuedAt,payload_json::text PayloadJson FROM valorapesquisa.certificates WHERE organization_id=@o AND id=@id",new{o,id});} public async Task<CertificateDto?> GetByResponseAsync(Guid o,Guid responseId){using var c=f.Create(); return await c.QueryFirstOrDefaultAsync<CertificateDto>("SELECT id,organization_id OrganizationId,survey_id SurveyId,response_id ResponseId,participant_name ParticipantName,participant_email_masked ParticipantEmailMasked,company_name CompanyName,total_score TotalScore,level,validation_code ValidationCode,validation_url ValidationUrl,status,issued_at IssuedAt,payload_json::text PayloadJson FROM valorapesquisa.certificates WHERE organization_id=@o AND response_id=@responseId",new{o,responseId});} public async Task<IReadOnlyList<CertificateDto>> ListAsync(Guid o){using var c=f.Create(); return (await c.QueryAsync<CertificateDto>("SELECT id,organization_id OrganizationId,survey_id SurveyId,response_id ResponseId,participant_name ParticipantName,participant_email_masked ParticipantEmailMasked,company_name CompanyName,total_score TotalScore,level,validation_code ValidationCode,validation_url ValidationUrl,status,issued_at IssuedAt,payload_json::text PayloadJson FROM valorapesquisa.certificates WHERE organization_id=@o ORDER BY issued_at DESC",new{o})).ToList();} public async Task<CertificateDto> CreateAsync(Guid o,Guid? s,Guid r,string? p,string? e,string? company,decimal? score,string? level,string code,string url,string payload){using var c=f.Create(); return await c.QuerySingleAsync<CertificateDto>(@"INSERT INTO valorapesquisa.certificates(organization_id,survey_id,response_id,participant_name,participant_email_masked,company_name,total_score,level,validation_code,validation_url,status,issued_at,payload_json) VALUES(@o,@s,@r,@p,@e,@company,@score,@level,@code,@url,'issued',now(),CAST(@payload AS jsonb)) RETURNING id,organization_id OrganizationId,survey_id SurveyId,response_id ResponseId,participant_name ParticipantName,participant_email_masked ParticipantEmailMasked,company_name CompanyName,total_score TotalScore,level,validation_code ValidationCode,validation_url ValidationUrl,status,issued_at IssuedAt,payload_json::text PayloadJson",new{o,s,r,p,e,company,score,level,code,url,payload});} public async Task RevokeAsync(Guid o,Guid id){using var c=f.Create(); await c.ExecuteAsync("UPDATE valorapesquisa.certificates SET status='revoked',updated_at=now() WHERE organization_id=@o AND id=@id",new{o,id});} public async Task<CertificateValidationDto?> ValidateAsync(string code,string? ipHash,string? userAgent){using var c=f.Create(); var r=await c.QueryFirstOrDefaultAsync<CertificateValidationDto>("SELECT (status='issued') Valid,status,validation_code ValidationCode,participant_name ParticipantName,company_name CompanyName,level,issued_at IssuedAt FROM valorapesquisa.certificates WHERE validation_code=@code",new{code}); await c.ExecuteAsync("INSERT INTO valorapesquisa.certificate_validations(certificate_id,validation_code,status,validated_at,validation_ip_hash,user_agent) SELECT id,@code,COALESCE(@status,'not_found'),now(),@ipHash,@userAgent FROM valorapesquisa.certificates WHERE validation_code=@code",new{code,status=r?.Status??"not_found",ipHash,userAgent}); return r;}}
public sealed class ExportRepository(IDbConnectionFactory f):IExportRepository{ public async Task<ExportJobDto> CreateAsync(Guid o,Guid? u,string entity,string format,string? filterJson){using var c=f.Create(); return await c.QuerySingleAsync<ExportJobDto>("INSERT INTO valorapesquisa.export_jobs(organization_id,requested_by,entity,format,status,filter_json) VALUES(@o,@u,@entity,@format,'queued',CAST(COALESCE(@filterJson,'{}') AS jsonb)) RETURNING id,organization_id OrganizationId,requested_by RequestedBy,entity,format,status,result_file_name ResultFileName,result_mime_type ResultMimeType,result_payload ResultPayload,created_at CreatedAt,completed_at CompletedAt,error_message ErrorMessage",new{o,u,entity,format,filterJson});} public async Task CompleteAsync(Guid o,Guid id,string fileName,string mimeType,string payload){using var c=f.Create(); await c.ExecuteAsync("UPDATE valorapesquisa.export_jobs SET status='completed',result_file_name=@fileName,result_mime_type=@mimeType,result_payload=@payload,completed_at=now() WHERE organization_id=@o AND id=@id",new{o,id,fileName,mimeType,payload});} public async Task<IReadOnlyList<ExportJobDto>> ListAsync(Guid o){using var c=f.Create(); return (await c.QueryAsync<ExportJobDto>("SELECT id,organization_id OrganizationId,requested_by RequestedBy,entity,format,status,result_file_name ResultFileName,result_mime_type ResultMimeType,result_payload ResultPayload,created_at CreatedAt,completed_at CompletedAt,error_message ErrorMessage FROM valorapesquisa.export_jobs WHERE organization_id=@o ORDER BY created_at DESC",new{o})).ToList();} public async Task<ExportJobDto?> GetAsync(Guid o,Guid id){using var c=f.Create(); return await c.QueryFirstOrDefaultAsync<ExportJobDto>("SELECT id,organization_id OrganizationId,requested_by RequestedBy,entity,format,status,result_file_name ResultFileName,result_mime_type ResultMimeType,result_payload ResultPayload,created_at CreatedAt,completed_at CompletedAt,error_message ErrorMessage FROM valorapesquisa.export_jobs WHERE organization_id=@o AND id=@id",new{o,id});}}
public sealed class LgpdRepository(IDbConnectionFactory f):ILgpdRepository{ public async Task<LgpdConsentDto> AddConsentAsync(RegisterLgpdConsentRequest r,string emailHash,string? ip,string? ua){using var c=f.Create(); return await c.QuerySingleAsync<LgpdConsentDto>("INSERT INTO valorapesquisa.lgpd_consents(organization_id,survey_id,response_id,participant_email_hash,consent_text,consent_version,accepted,accepted_at,ip_hash,user_agent) VALUES(@OrganizationId,@SurveyId,@ResponseId,@emailHash,@ConsentText,@ConsentVersion,@Accepted,CASE WHEN @Accepted THEN now() ELSE NULL END,@ip,@ua) RETURNING id,organization_id OrganizationId,survey_id SurveyId,response_id ResponseId,consent_version ConsentVersion,accepted,accepted_at AcceptedAt,created_at CreatedAt",new{r.OrganizationId,r.SurveyId,r.ResponseId,emailHash,r.ConsentText,r.ConsentVersion,r.Accepted,ip,ua});} public async Task<IReadOnlyList<LgpdConsentDto>> ListConsentsAsync(Guid o){using var c=f.Create(); return (await c.QueryAsync<LgpdConsentDto>("SELECT id,organization_id OrganizationId,survey_id SurveyId,response_id ResponseId,consent_version ConsentVersion,accepted,accepted_at AcceptedAt,created_at CreatedAt FROM valorapesquisa.lgpd_consents WHERE organization_id=@o ORDER BY created_at DESC",new{o})).ToList();} public async Task<PrivacyRequestDto> CreateRequestAsync(CreatePrivacyRequestRequest r,string h,string m){using var c=f.Create(); return await c.QuerySingleAsync<PrivacyRequestDto>("INSERT INTO valorapesquisa.privacy_requests(organization_id,requester_email_hash,requester_email_masked,request_type,protocol,status,description,response_id,requested_at) VALUES(@OrganizationId,@h,@m,@RequestType,@protocol,'open',@Description,@ResponseId,now()) RETURNING id,organization_id OrganizationId,requester_email_masked RequesterEmailMasked,request_type RequestType,protocol,status,description,response_id ResponseId,requested_at RequestedAt,completed_at CompletedAt,result_json::text ResultJson",new{r.OrganizationId,h,m,r.RequestType,protocol=$"LGPD-{DateTime.UtcNow:yyyyMMdd}-{Guid.NewGuid():N}"[..24].ToUpperInvariant(),r.Description,r.ResponseId});} public async Task<PrivacyRequestDto?> GetRequestAsync(string protocol){using var c=f.Create(); return await c.QueryFirstOrDefaultAsync<PrivacyRequestDto>("SELECT id,organization_id OrganizationId,requester_email_masked RequesterEmailMasked,request_type RequestType,protocol,status,description,response_id ResponseId,requested_at RequestedAt,completed_at CompletedAt,result_json::text ResultJson FROM valorapesquisa.privacy_requests WHERE protocol=@protocol",new{protocol});} public async Task<PrivacyRequestDto?> GetRequestByIdAsync(Guid id){using var c=f.Create(); return await c.QueryFirstOrDefaultAsync<PrivacyRequestDto>("SELECT id,organization_id OrganizationId,requester_email_masked RequesterEmailMasked,request_type RequestType,protocol,status,description,response_id ResponseId,requested_at RequestedAt,completed_at CompletedAt,result_json::text ResultJson FROM valorapesquisa.privacy_requests WHERE id=@id",new{id});} public async Task<IReadOnlyList<PrivacyRequestDto>> ListRequestsAsync(Guid? o){using var c=f.Create(); return (await c.QueryAsync<PrivacyRequestDto>("SELECT id,organization_id OrganizationId,requester_email_masked RequesterEmailMasked,request_type RequestType,protocol,status,description,response_id ResponseId,requested_at RequestedAt,completed_at CompletedAt,result_json::text ResultJson FROM valorapesquisa.privacy_requests WHERE (@o IS NULL OR organization_id=@o) ORDER BY requested_at DESC",new{o})).ToList();} public async Task UpdateStatusAsync(Guid o,Guid id,string status,Guid? h){using var c=f.Create(); await c.ExecuteAsync("UPDATE valorapesquisa.privacy_requests SET status=@status,handled_by=@h,updated_at=now() WHERE organization_id=@o AND id=@id",new{o,id,status,h});} public async Task CompleteAsync(Guid o,Guid id,string resultJson,Guid? h){using var c=f.Create(); await c.ExecuteAsync("UPDATE valorapesquisa.privacy_requests SET status='completed',result_json=CAST(@resultJson AS jsonb),completed_at=now(),handled_by=@h,updated_at=now() WHERE organization_id=@o AND id=@id",new{o,id,resultJson,h});}}
public sealed class EmailOperationalRepository(IDbConnectionFactory f):IEmailOperationalRepository{ static string Mask(string to)=>string.IsNullOrWhiteSpace(to)||!to.Contains('@')?"***":$"{to[0]}***@{to.Split('@')[1]}"; public async Task<IReadOnlyList<EmailTemplateDto>> ListTemplatesAsync(Guid? o){using var c=f.Create(); return (await c.QueryAsync<EmailTemplateDto>("SELECT id,organization_id OrganizationId,code,name,subject,body_html BodyHtml,body_text BodyText,status FROM valorapesquisa.email_templates WHERE is_deleted=false AND (@o IS NULL OR organization_id IS NULL OR organization_id=@o) ORDER BY code",new{o})).ToList();} public async Task<EmailTemplateDto> UpsertTemplateAsync(Guid? id,UpsertEmailTemplateRequest r){using var c=f.Create(); return await c.QuerySingleAsync<EmailTemplateDto>(@"INSERT INTO valorapesquisa.email_templates(id,organization_id,code,name,subject,body_html,body_text,status) VALUES(COALESCE(@id,gen_random_uuid()),@OrganizationId,@Code,@Name,@Subject,@BodyHtml,@BodyText,@Status) ON CONFLICT (code,organization_id) DO UPDATE SET name=EXCLUDED.name,subject=EXCLUDED.subject,body_html=EXCLUDED.body_html,body_text=EXCLUDED.body_text,status=EXCLUDED.status,updated_at=now() RETURNING id,organization_id OrganizationId,code,name,subject,body_html BodyHtml,body_text BodyText,status",new{id,r.OrganizationId,r.Code,r.Name,r.Subject,r.BodyHtml,r.BodyText,r.Status});} public async Task<EmailJobDto> QueueAsync(Guid? o,Guid? r,Guid? cert,string template,string to,string subject,string html,string? text){using var c=f.Create(); return await c.QuerySingleAsync<EmailJobDto>(@"INSERT INTO valorapesquisa.email_jobs(organization_id,response_id,certificate_id,template_code,from_email,from_name,to_email_masked,to_email_encrypted_or_plain_dev,subject,body_html,body_text,status,next_attempt_at) VALUES(@o,@r,@cert,@template,COALESCE(current_setting('valora.smtp_from_email',true),'no-reply@localhost'),COALESCE(current_setting('valora.smtp_from_name',true),'Valora'),@masked,@to,@subject,@html,@text,'queued',now()) RETURNING id,organization_id OrganizationId,response_id ResponseId,certificate_id CertificateId,template_code TemplateCode,from_email FromEmail,from_name FromName,to_email_masked ToEmailMasked,subject,status,attempts,next_attempt_at NextAttemptAt,last_attempt_at LastAttemptAt,sent_at SentAt,dead_letter_reason DeadLetterReason,created_at CreatedAt",new{o,r,cert,template,to,masked=Mask(to),subject,html,text});} public async Task<IReadOnlyList<EmailJobDto>> ListJobsAsync(Guid? o,string? status=null){using var c=f.Create(); return (await c.QueryAsync<EmailJobDto>("SELECT id,organization_id OrganizationId,response_id ResponseId,certificate_id CertificateId,template_code TemplateCode,from_email FromEmail,from_name FromName,to_email_masked ToEmailMasked,subject,status,attempts,next_attempt_at NextAttemptAt,last_attempt_at LastAttemptAt,sent_at SentAt,dead_letter_reason DeadLetterReason,created_at CreatedAt FROM valorapesquisa.email_jobs WHERE (@o IS NULL OR organization_id=@o) AND (@status IS NULL OR status=@status) ORDER BY created_at DESC",new{o,status})).ToList();} public async Task<EmailJobDto?> GetJobAsync(Guid id){using var c=f.Create(); return await c.QueryFirstOrDefaultAsync<EmailJobDto>("SELECT id,organization_id OrganizationId,response_id ResponseId,certificate_id CertificateId,template_code TemplateCode,from_email FromEmail,from_name FromName,to_email_masked ToEmailMasked,subject,status,attempts,next_attempt_at NextAttemptAt,last_attempt_at LastAttemptAt,sent_at SentAt,dead_letter_reason DeadLetterReason,created_at CreatedAt FROM valorapesquisa.email_jobs WHERE id=@id",new{id});} public async Task MarkProcessingAsync(Guid id){using var c=f.Create(); await c.ExecuteAsync("UPDATE valorapesquisa.email_jobs SET status='processing',attempts=attempts+1,last_attempt_at=now() WHERE id=@id",new{id});} public async Task MarkSentAsync(Guid id){using var c=f.Create(); await c.ExecuteAsync("UPDATE valorapesquisa.email_jobs SET status='sent',sent_at=now(),updated_at=now() WHERE id=@id",new{id});} public async Task MarkFailedAsync(Guid id,string reason,bool dead){using var c=f.Create(); await c.ExecuteAsync("UPDATE valorapesquisa.email_jobs SET status=@status,dead_letter_reason=@reason,next_attempt_at=CASE WHEN @dead THEN NULL ELSE now()+interval '5 minutes' END,updated_at=now() WHERE id=@id",new{id,reason,status=dead?"dead_letter":"failed",dead});} public async Task<EmailStatusDto> StatusAsync(Guid? o,bool dev){using var c=f.Create(); var rows=(await c.QueryAsync<(string Status,int Count)>("SELECT status, count(*)::int Count FROM valorapesquisa.email_jobs WHERE (@o IS NULL OR organization_id=@o) GROUP BY status",new{o})).ToDictionary(x=>x.Status,x=>x.Count); return new EmailStatusDto(rows.GetValueOrDefault("queued"),rows.GetValueOrDefault("processing"),rows.GetValueOrDefault("sent"),rows.GetValueOrDefault("failed"),rows.GetValueOrDefault("dead_letter"),dev);}}
